parameters.jsonOutput:
={{
  (() => {
    try {
      // 1. FIXED: Get data from the LOOP node instead of the Trigger
      // This ensures it works for both "Live" and "Scheduled" runs.
      const originalData = $('Loop Over Items1').item.json;

      // 2. Get AI response (from current input)
      const aiResponseParts = $json.content?.parts;

      // Safety check: did AI return anything?
      if (!aiResponseParts || !aiResponseParts[0] || !aiResponseParts[0].text) {
        return { ...originalData, error: "AI returned empty response" };
      }

      const rawText = aiResponseParts[0].text;

      // 3. Clean Markdown formatting (look for JSON brackets { ... })
      const firstBracket = rawText.indexOf('{');
      const lastBracket = rawText.lastIndexOf('}');

      let cleanJsonString = rawText;
      if (firstBracket !== -1 && lastBracket !== -1) {
        cleanJsonString = rawText.substring(firstBracket, lastBracket + 1);
      }

      // 4. Parse text to Object
      const scoreCardData = JSON.parse(cleanJsonString);

      // 5. Merge Data (Original from Loop + Score Card Result)
      return { ...originalData, ...scoreCardData };

    } catch (e) {
      // Fallback: Return whatever data we can find + error message
      let fallbackData = {};
      try { 
        // Try getting data from Loop node in catch block too
        fallbackData = $('Loop Over Items1').item.json; 
      } catch(err) { 
        fallbackData = $json; 
      }

      return { 
        ...fallbackData, 
        error: "JSON Parse Error: " + e.message,
        raw_ai_output: $json.content?.parts?.[0]?.text 
      };
    }
  })()
}}
